features.snippet:
localparam [3:0] s0=0, s1=1, s2=2, s3=3;
reg [1:0] ps, ns;
always @(posedge clk) begin
    if (~rstn) ps <= s0;
    else       ps <= ns;
end
always @(*) begin
    ns = ps;
    case (ps)
        s0: if (start)   ns = s1;
        s1: if (cond_a)  ns = s2;
        s2: if (cond_b)  ns = s3;
        s3: if (cond_c)  ns = s0;
    endcase
end

wire [3:0] a, b, c, d;
wire all_set;
assign all_set = &({a, b, c, d});

reg [1:0] ps;
wire cond;
always @(posedge clk)
    if (ps == 2'h2 && cond) assert (ps == 2'h3);

assert_always_i: assert property (
    @(posedge clk) disable iff (!rstn)
    precondition |-> condition
);

module assert_always (
    input wire event_m, disable_e, precondition, condition
);
    always @(*) assume (disable_e == 1'b1);
    always @(posedge event_m)
        if (precondition) assert (condition);
endmodule

